// Beschreibe diese Funktion …
async function datum_setzen(frist, datum_komplett) {
  if (frist == '2') {
    resultat = 'übermorgen';
  } else if (frist == '1') {
    resultat = 'morgen';
  } else if (frist == '0') {
    resultat = 'heute';
  } else {
    resultat = [formatDate(getDateObject(datum_komplett), 'W', 'de'),'., ',formatDate(getDateObject(datum_komplett), 'TT.MM.')].join('');
  }
  return resultat;
}

// Beschreibe diese Funktion …
async function text_k_C3_BCrzen(text) {
    const excludes = ["Gartenabfälle", "Schadstoffmobil", "Weihnachtsbäume"];
    const input = text.split(", ");
    const result = [];
    for (let candidate of input) {
        if (excludes.includes(candidate)) {
            continue;
        }
        result.push(candidate)
    }
    return result.join(", ");
}

// Beschreibe diese Funktion …
async function schalte_ger_C3_A4te(parameter) {
  console.info(('Geräte schalten mit: ' + String(parameter)));
  // Receiver schalten
  if (parameter[0] == 'ein') {
    console.info((['Schalte den Receiver ein; Wiedergabe: ',parameter[1],', Programm: ',parameter[2],', Lautstärke: ',parameter[3]].join('')));
    if (getState('denon.0.zoneMain.powerZone').val == false) {
      setState('denon.0.zoneMain.powerZone' /* Main Zone Power State */, true);
      await wait(6000);
    }
    setState('denon.0.zoneMain.volume' /* Main Volume */, 5);
    setState('denon.0.zoneMain.selectInput' /* Select input */, (parameter[1]));
    setState('denon.0.zoneMain.volume' /* Main Volume */, parseFloat((parameter[3])));
  } else {
    console.info('Schalte den Receiver aus; Wiedergabe: TV Audio, Programm: n/a, Lautstärke: 40');
    setState('denon.0.zoneMain.volume' /* Main Volume */, 5);
    setState('denon.0.zoneMain.selectInput' /* Select input */, 'TV');
    setState('denon.0.zoneMain.volume' /* Main Volume */, 40);
    setState('denon.0.zoneMain.powerZone' /* Main Zone Power State */, false);
  }
  // TV schalten
  if (parameter[4] == 'ein') {
    console.info(('Schalte den Fernseher ein; App: ' + String(parameter[5])));
  } else {
    console.info('Schalte den Fernseher aus.');
  }
}

