// Beschreibe diese Funktion …
async function schalte_av(programm) {
  console.info(('AV schalten mit: ' + String(programm)));
  await Setze_LEDs_zur_C3_BCck();

  switch (programm) {
  	case 'pfau':
    console.info('Schalte HR1 ein.');
    await schalte_ger_C3_A4te(['ein', 'TUNER', 'hr1', '16', 'aus', '6', '7', '8', '9', '10']);
    setState('mqtt.0.button.btn_fa21e8.3-2.state' /* button/btn_fa21e8/3-2/state */, 'true');

  		break;
  	case 'dave':
    console.info('Schalte Affinity Radio ein.');
    await schalte_ger_C3_A4te(['ein', 'NET', 'affinity', '26', 'aus', '6', '7', '8', '9', '10']);
    setState('mqtt.0.button.btn_fa21e8.4-2.state' /* button/btn_fa21e8/4-2/state */, 'true');

  		break;
  	case 'planimal':
    console.info('Schalte Live TV ein.');
    await schalte_ger_C3_A4te(['ein', 'TV', '3', '40', 'ein', 'ocilion', '7', '8', '9', '10']);
    setState('mqtt.0.button.btn_fa21e8.5-2.state' /* button/btn_fa21e8/5-2/state */, 'true');

  		break;
  	case 'fussi':
    console.info('Schalte Sky ein.');
    await schalte_ger_C3_A4te(['ein', 'TV', '3', '40', 'ein', 'sky', '7', '8', '9', '10']);
    setState('mqtt.0.button.btn_fa21e8.6-2.state' /* button/btn_fa21e8/6-2/state */, 'true');

  		break;
  	case '49ers':
    console.info('Schalte DAZN ein.');
    await schalte_ger_C3_A4te(['ein', 'tv', '3', '40', 'ein', 'dazn', '7', '8', '9', '10']);
    setState('mqtt.0.button.btn_fa21e8.7-2.state' /* button/btn_fa21e8/7-2/state */, 'true');

  		break;
  	case 'binge':
    console.info('Schalte Netflix ein.');
    await schalte_ger_C3_A4te(['ein', 'tv', '3', '40', 'ein', 'netflix', '7', '8', '9', '10']);
    setState('mqtt.0.button.btn_fa21e8.8-2.state' /* button/btn_fa21e8/8-2/state */, 'true');

  		break;
  	case 'aus':
    console.info('Schalte Receiver und TV aus.');
    await schalte_ger_C3_A4te(['aus', '2', '3', '4', 'aus', '6', '7', '8', '9', '10']);

  		break;
  	default:
    console.info((['Das hätte jetzt so nicht passieren sollen… „programm“ enthält: „',programm,'“.'].join('')));

  		break;
  }
}

