// Nächste Müllabfuhr setzen
schedule('{"time":{"exactTime":true,"start":"00:01"},"period":{"days":1}}', async () => {
  art = await text_k_C3_BCrzen(getState('trashschedule.0.next.typesText').val);
  if (art == '') {
    art = await text_k_C3_BCrzen(getState('trashschedule.0.nextAfter.typesText').val);
    Datum = await datum_setzen(getState('trashschedule.0.nextAfter.daysLeft').val, getState('trashschedule.0.nextAfter.date').val);
  } else {
    Datum = await datum_setzen(getState('trashschedule.0.next.daysLeft').val, getState('trashschedule.0.next.date').val);
  }
  if (art == '') {
    setState('mqtt.0.data.events.trash' /* data/events/trash */, 'Bitte Kalender');
    setState('mqtt.0.data.events.trashdate' /* data/events/trashdate */, 'prüfen!');
  } else {
    setState('mqtt.0.data.events.trash' /* data/events/trash */, art);
    setState('mqtt.0.data.events.trashdate' /* data/events/trashdate */, Datum);
  }
  setState('0_userdata.0.trigger.scripts.erinnerungen.müll_abgeholt' /* müll_abgeholt */, false);
});
// Müll abgeholt quittieren
on({ id: 'zigbee.0.00158d0007c585bf.hold' /* hold */, val: true }, async (obj) => {
  let value = obj.state.val;
  let oldValue = obj.oldState.val;
  if ((!getState('0_userdata.0.trigger.scripts.erinnerungen.müll_abgeholt').val) && (getState('mqtt.0.data.events.trashdate').val == 'heute')) {
    setState('sonoff.0.Alarm.POWER' /* Alarm POWER */, true);
    art = await text_k_C3_BCrzen(getState('trashschedule.0.nextAfter.typesText').val);
    Datum = await datum_setzen(getState('trashschedule.0.nextAfter.daysLeft').val, getState('trashschedule.0.nextAfter.date').val);
    if (art == '') {
      setState('mqtt.0.data.events.trash' /* data/events/trash */, 'Bitte Kalender');
      setState('mqtt.0.data.events.trashdate' /* data/events/trashdate */, 'prüfen!');
    } else {
      setState('mqtt.0.data.events.trash' /* data/events/trash */, art);
      setState('mqtt.0.data.events.trashdate' /* data/events/trashdate */, Datum);
    }
    setState('0_userdata.0.trigger.scripts.erinnerungen.müll_abgeholt' /* müll_abgeholt */, true);
    console.info((['Nächste Leerung: ',getState('mqtt.0.data.events.trash').val,', nächster Termin: ',getState('mqtt.0.data.events.trashdate').val].join('')));
    setStateDelayed('sonoff.0.Alarm.POWER' /* Alarm POWER */, false, 3000, false);
    await send_signal('WHITE', 'on', 3);
  } else {
    await send_signal('WHITE', 'fast_blink', 3);
  }
});
